-- ============================================================
-- Full expense seed from Airtable KUNCH_11 (2,710 records with vendors)
-- Run AFTER migrations 036 and 037 (vendor unique constraint + vendor seed)
-- Paid expenses → finance_approved (no further workflow needed)
-- Unpaid expenses → pending
-- Safe to re-run: ON CONFLICT (expense_code) DO UPDATE
-- ============================================================

CREATE TEMP TABLE IF NOT EXISTS _exp_import (
  expense_code   TEXT,
  description    TEXT,
  amount         NUMERIC,
  expense_date   DATE,
  paid           BOOLEAN,
  vendor_name    TEXT,
  expense_type   TEXT
);


-- continued...

-- continued...

-- continued...

-- continued...

-- continued...

-- Link expenses to vendors and set approval status
  expense_code, item_service_description, amount_etb, date,
  payment_status, approval_status, expense_type, vendors_name, vendor_id
)
SELECT
  i.expense_code,
  i.description,
  i.amount,
  i.expense_date,
  i.paid,
  CASE WHEN i.paid THEN 'finance_approved'::text ELSE 'pending'::text END,
  i.expense_type,
  i.vendor_name,
  (SELECT id FROM vendors
   WHERE lower(trim(vendor_name)) = lower(trim(i.vendor_name))
   LIMIT 1)
FROM _exp_import i
ON CONFLICT (expense_code) DO UPDATE SET
  vendor_id       = EXCLUDED.vendor_id,
  payment_status  = EXCLUDED.payment_status,
  approval_status = CASE
                      WHEN EXCLUDED.payment_status = true THEN 'finance_approved'
                      ELSE expenses.approval_status  -- don't downgrade existing approvals
                    END;

DROP TABLE IF EXISTS _exp_import;

-- Verify
SELECT
  approval_status,
  COUNT(*) AS count,
  SUM(amount_etb) AS total_etb
FROM expenses
WHERE vendor_id IS NOT NULL
GROUP BY approval_status
ORDER BY approval_status;